-- ----------------------------
-- Table structure for daily_record
-- ----------------------------
DROP TABLE IF EXISTS `daily_record`;
CREATE TABLE `daily_record`  (
  `record_id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL,
  `record_date` date NOT NULL COMMENT '记录日期',
  `weight` decimal(5, 2) NULL DEFAULT NULL COMMENT '体重',
  `blood_pressure_high` int NULL DEFAULT NULL COMMENT '收缩压',
  `blood_pressure_low` int NULL DEFAULT NULL COMMENT '舒张压',
  `blood_sugar` decimal(4, 1) NULL DEFAULT NULL COMMENT '血糖',
  `fetal_movement` int NULL DEFAULT NULL COMMENT '胎动次数',
  `feeling` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '身体感受标签',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`record_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 16 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '每日健康记录表' ROW_FORMAT = Dynamic;

