INSERT INTO `doctor_info` VALUES (6, 'DOC002', '副主任医师', '营养科', '妊娠期糖尿病饮食管理、孕期体重控制', '国家注册营养师，擅长通过饮食干预解决孕期血糖、血压问题，帮助孕妈长胎不长肉。', 89);
