INSERT INTO `knowledge_base` VALUES (1, NULL, '测试', '测试案例', '孕期营养', 1, '2025-11-25 00:26:59');
INSERT INTO `knowledge_base` VALUES (2, NULL, '孕期能不能吃辣？专家告诉你真相', '很多孕妈在怀孕期间口味会发生变化，特别想吃辣。其实，适量吃辣是可以的，但要注意以下几点：\n1. 避免肠胃不适：辣椒刺激肠胃，容易引起便秘或烧心。\n2. 注意食材卫生：外面吃火锅要注意食材是否煮熟。\n3. 适可而止：如果你本身有痔疮或胃病，建议少吃。\n\n总结：解馋可以，不要贪多哦！', '孕期营养', 1207, '2025-11-25 00:30:28');
INSERT INTO `knowledge_base` VALUES (3, NULL, '糖耐量检测(OGTT)全攻略，一次通过！', '糖耐量检测通常在孕24-28周进行。为了顺利通过，建议：\n1. 检查前三天正常饮食，不要刻意控糖，也不要暴饮暴食。\n2. 检查前一晚22点后禁食禁水。\n3. 喝糖水时不要大口吞咽，建议5分钟内喝完。\n4. 等待期间静坐休息，不要剧烈运动。', '产检科普', 2342, '2025-11-25 00:30:28');
INSERT INTO `knowledge_base` VALUES (4, NULL, '待产包里到底要装什么？超全清单', '入院待产包清单：\n【证件类】：身份证、医保卡、产检档案、准生证。\n【妈妈用品】：产褥垫(重要)、卫生巾、一次性内裤、吸管杯、防滑拖鞋、哺乳内衣。\n【宝宝用品】：NB码纸尿裤、和尚服2-3套、包被、抚触油、护臀膏。\n【其他】：充电宝、零食(巧克力/红牛)。', '分娩知识', 5600, '2025-11-25 00:30:28');
INSERT INTO `knowledge_base` VALUES (5, NULL, '产后涨奶痛怎么办？这几招很管用', '涨奶是很多新手妈妈的噩梦。缓解方法：\n1. 早接触、早吸吮：宝宝是最好的吸奶器。\n2. 冷敷：涨痛严重时可用卷心菜叶或冰袋冷敷避开乳头。\n3. 温水淋浴：喂奶前温敷有助于乳汁流出。\n4. 寻求专业通乳师帮助，切勿暴力按揉。', '产后护理', 890, '2025-11-25 00:30:28');
INSERT INTO `knowledge_base` VALUES (6, NULL, '孕期补钙，吃这些比钙片还好', '孕中晚期对钙的需求量增加。除了钙片，这些食物也是补钙高手：\n1. 牛奶及奶制品：吸收率高。\n2. 绿叶蔬菜：如小油菜、小白菜，钙含量不输牛奶。\n3. 豆制品：北豆腐、豆腐干。\n4. 芝麻酱：偶尔吃一点，补钙又补铁。', '孕期营养', 1561, '2025-11-25 00:30:28');
INSERT INTO `knowledge_base` VALUES (7, NULL, '为什么要做NT检查？错过了怎么办？', 'NT检查是通过B超测量胎儿颈后透明层厚度，用于早期筛查唐氏综合征等染色体异常。最佳时间是11周-13周+6天。如果错过了这个时间，颈后透明层会被吸收，无法测量，只能通过后续的唐氏筛查或无创DNA来评估风险。', '产检科普', 3101, '2025-11-25 00:30:28');

-- ----------------------------
-- Table structure for mall_order
-- ----------------------------
DROP TABLE IF EXISTS `mall_order`;
CREATE TABLE `mall_order`  (
  `order_id` bigint NOT NULL AUTO_INCREMENT,
  `order_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '订单编号',
  `user_id` bigint NOT NULL,
  `product_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `product_img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `price` decimal(10, 2) NULL DEFAULT NULL,
  `status` int NULL DEFAULT 0 COMMENT '0-待支付, 1-已支付',
  `create_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `pay_time` datetime(0) NULL DEFAULT NULL,
  PRIMARY KEY (`order_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '商城订单表' ROW_FORMAT = Dynamic;

